### Final Recommended Version:

```js
/**
 * Safely renders HTML content after sanitization.
 * @param {string} userInput - The HTML string to render
 */
function renderHTML(userInput) {
  if (typeof userInput !== 'string') {
    console.warn('renderHTML: Expected string input');
    return;
  }

  const output = document.getElementById('output');
  if (!output) {
    console.error('renderHTML: Target element #output not found');
    return;
  }

  // Critical: Always sanitize user-controlled HTML
  output.innerHTML = DOMPurify.sanitize(userInput, {
    ALLOWED_TAGS: ['b', 'i', 'em', 'strong', 'p', 'br', 'ul', 'ol', 'li'], // whitelist if possible
    ALLOWED_ATTR: ['class']
  });
}
```

